from __future__ import annotations

import json
import subprocess
import urllib.error
import urllib.parse
import urllib.request
import uuid
from datetime import datetime, timezone
from typing import Any

from app.memory.models import MemoryEntry


def _is_uuid(raw: str | None) -> bool:
    if not raw:
        return False
    try:
        uuid.UUID(str(raw))
        return True
    except ValueError:
        return False


def _tenant_uuid(tenant_id: str) -> str:
    if _is_uuid(tenant_id):
        return tenant_id
    return str(uuid.uuid5(uuid.NAMESPACE_URL, f"tenant:{tenant_id}"))


def _group_uuid(group_id: str | None) -> str | None:
    if _is_uuid(group_id):
        return group_id
    return None


def _dt_from_iso(raw: str | None) -> datetime | None:
    if not raw:
        return None
    try:
        return datetime.fromisoformat(raw.replace("Z", "+00:00"))
    except ValueError:
        return None


def _vector_to_pg(raw: list[float] | None) -> str | None:
    if not raw:
        return None
    return "[" + ",".join(f"{v:.8f}" for v in raw) + "]"


def _vector_from_pg(raw: Any) -> list[float] | None:
    if raw is None:
        return None
    if isinstance(raw, list):
        return [float(v) for v in raw]
    if isinstance(raw, str):
        text = raw.strip()
        if text.startswith("[") and text.endswith("]"):
            body = text[1:-1].strip()
            if not body:
                return []
            return [float(part.strip()) for part in body.split(",")]
    return None


class SupabaseMemoryRepository:
    def __init__(self, supabase_url: str, service_role_key: str) -> None:
        self._base = supabase_url.rstrip("/")
        self._key = service_role_key

    def create(self, entry: MemoryEntry) -> MemoryEntry:
        tenant_uuid = _tenant_uuid(entry.tenant_id)
        self._ensure_tenant(tenant_uuid=tenant_uuid, tenant_name=entry.tenant_id)
        self._ensure_agent(tenant_uuid=tenant_uuid, agent_id=entry.owner_agent_id)

        row = {
            "id": entry.id,
            "tenant_id": tenant_uuid,
            "owner_agent_id": entry.owner_agent_id,
            "group_id": _group_uuid(entry.group_id),
            "scope": entry.scope,
            "entry_type": entry.entry_type,
            "content": entry.content,
            "content_hash": entry.content_hash,
            "importance": int(entry.importance),
            "confidence": float(entry.confidence),
            "valid_from": entry.valid_from.isoformat() if entry.valid_from else None,
            "valid_until": entry.valid_until.isoformat() if entry.valid_until else None,
            "tags": entry.tags,
            "source_ref": entry.source_ref,
            "metadata": entry.metadata or {},
            "embedding": _vector_to_pg(entry.embedding),
        }
        resp = self._request_json(
            "POST",
            "/rest/v1/memory_entries?select=*",
            payload=row,
            headers={"Prefer": "return=representation"},
        )
        if not isinstance(resp, list) or not resp:
            return entry
        return self._row_to_entry(resp[0], tenant_alias=entry.tenant_id)

    def get(self, memory_id: str, tenant_id: str) -> MemoryEntry | None:
        tenant_uuid = _tenant_uuid(tenant_id)
        q = urllib.parse.urlencode({"id": f"eq.{memory_id}", "tenant_id": f"eq.{tenant_uuid}", "select": "*"})
        resp = self._request_json("GET", f"/rest/v1/memory_entries?{q}")
        if not isinstance(resp, list) or not resp:
            return None
        return self._row_to_entry(resp[0], tenant_alias=tenant_id)

    def list_by_tenant(self, tenant_id: str) -> list[MemoryEntry]:
        tenant_uuid = _tenant_uuid(tenant_id)
        q = urllib.parse.urlencode({"tenant_id": f"eq.{tenant_uuid}", "select": "*", "order": "created_at.desc"})
        resp = self._request_json("GET", f"/rest/v1/memory_entries?{q}")
        if not isinstance(resp, list):
            return []
        return [self._row_to_entry(row, tenant_alias=tenant_id) for row in resp]

    def _ensure_tenant(self, tenant_uuid: str, tenant_name: str) -> None:
        payload = {"id": tenant_uuid, "name": tenant_name}
        self._request_json(
            "POST",
            "/rest/v1/tenants",
            payload=payload,
            headers={"Prefer": "resolution=merge-duplicates,return=minimal"},
            query={"on_conflict": "id"},
        )

    def _ensure_agent(self, tenant_uuid: str, agent_id: str) -> None:
        payload = {"id": agent_id, "tenant_id": tenant_uuid, "name": agent_id, "override_mode": "none", "is_disabled": False}
        self._request_json(
            "POST",
            "/rest/v1/agents",
            payload=payload,
            headers={"Prefer": "resolution=merge-duplicates,return=minimal"},
            query={"on_conflict": "id"},
        )

    def _request_json(
        self,
        method: str,
        path: str,
        payload: dict[str, Any] | None = None,
        headers: dict[str, str] | None = None,
        query: dict[str, str] | None = None,
    ) -> Any:
        qs = ""
        if query:
            qs = ("&" if "?" in path else "?") + urllib.parse.urlencode(query)
        url = f"{self._base}{path}{qs}"
        body = None if payload is None else json.dumps(payload).encode("utf-8")
        req_headers = {
            "apikey": self._key,
            "Authorization": f"Bearer {self._key}",
            "Content-Type": "application/json",
        }
        if headers:
            req_headers.update(headers)
        req = urllib.request.Request(url=url, data=body, method=method, headers=req_headers)
        try:
            opener = urllib.request.build_opener(urllib.request.ProxyHandler({}))
            with opener.open(req, timeout=20) as resp:
                raw = resp.read().decode("utf-8")
                if not raw.strip():
                    return {}
                return json.loads(raw)
        except (urllib.error.URLError, OSError):
            return self._request_via_powershell(method=method, url=url, payload=payload, headers=req_headers)

    def _row_to_entry(self, row: dict[str, Any], tenant_alias: str) -> MemoryEntry:
        created = _dt_from_iso(row.get("created_at")) or datetime.now(tz=timezone.utc)
        return MemoryEntry(
            id=str(row.get("id")),
            tenant_id=tenant_alias,
            owner_agent_id=str(row.get("owner_agent_id")),
            scope=str(row.get("scope")),
            content=str(row.get("content", "")),
            group_id=row.get("group_id"),
            entry_type=str(row.get("entry_type", "message")),
            tags=list(row.get("tags") or []),
            source_ref=row.get("source_ref"),
            embedding=_vector_from_pg(row.get("embedding")),
            content_hash=row.get("content_hash"),
            importance=int(row.get("importance", 50)),
            confidence=float(row.get("confidence", 0.5)),
            valid_from=_dt_from_iso(row.get("valid_from")),
            valid_until=_dt_from_iso(row.get("valid_until")),
            metadata=dict(row.get("metadata") or {}),
            created_at=created,
        )

    def _request_via_powershell(
        self, *, method: str, url: str, payload: dict[str, Any] | None, headers: dict[str, str]
    ) -> Any:
        payload_json = json.dumps(payload) if payload is not None else ""
        header_lines: list[str] = []
        for key, value in headers.items():
            escaped = str(value).replace("'", "''")
            header_lines.append(f"$h['{key}'] = '{escaped}'")
        headers_ps = "; ".join(header_lines)
        if payload is not None:
            body_escaped = payload_json.replace("'", "''")
            body_ps = f"$body = '{body_escaped}'"
        else:
            body_ps = "$body = $null"
        script = (
            "$ErrorActionPreference='Stop'; "
            "$h=@{}; "
            f"{headers_ps}; "
            f"{body_ps}; "
            "$args = @{Uri='" + url.replace("'", "''") + "'; Method='" + method + "'; Headers=$h; TimeoutSec=20; UseBasicParsing=$true}; "
            "if ($body -ne $null) { $args['Body']=$body }; "
            "$resp = Invoke-WebRequest @args; "
            "if ([string]::IsNullOrWhiteSpace($resp.Content)) { '{}' } else { $resp.Content }"
        )
        completed = subprocess.run(
            ["powershell", "-NoProfile", "-Command", script],
            capture_output=True,
            text=True,
            check=False,
        )
        if completed.returncode != 0:
            raise RuntimeError(completed.stderr.strip() or completed.stdout.strip() or "powershell_request_failed")
        text = completed.stdout.strip()
        if not text:
            return {}
        return json.loads(text)

from __future__ import annotations

import uuid
from typing import Protocol

from app.memory.models import MemoryEntry


class MemoryRepository(Protocol):
    def create(self, entry: MemoryEntry) -> MemoryEntry:
        ...

    def get(self, memory_id: str, tenant_id: str) -> MemoryEntry | None:
        ...

    def list_by_tenant(self, tenant_id: str) -> list[MemoryEntry]:
        ...


class InMemoryMemoryRepository:
    def __init__(self) -> None:
        self._store: dict[tuple[str, str], MemoryEntry] = {}

    def create(self, entry: MemoryEntry) -> MemoryEntry:
        if not entry.id:
            entry.id = str(uuid.uuid4())
        self._store[(entry.tenant_id, entry.id)] = entry
        return entry

    def get(self, memory_id: str, tenant_id: str) -> MemoryEntry | None:
        return self._store.get((tenant_id, memory_id))

    def list_by_tenant(self, tenant_id: str) -> list[MemoryEntry]:
        return [entry for (stored_tenant, _), entry in self._store.items() if stored_tenant == tenant_id]

from __future__ import annotations

import math
from dataclasses import dataclass
from datetime import datetime, timezone
from typing import Any

from app.embeddings.service import EmbeddingService
from app.identity.models import IdentityContext
from app.memory.models import MemoryEntry
from app.memory.service import MemoryService
from app.permissions.policy_engine import PolicyEngine


@dataclass(frozen=True)
class RetrievalResult:
    items: list[dict[str, Any]]
    debug: dict[str, Any]


class MemoryRetrievalService:
    def __init__(self, memory_service: MemoryService, policy: PolicyEngine, embeddings: EmbeddingService) -> None:
        self._memory = memory_service
        self._policy = policy
        self._embeddings = embeddings

    def retrieve_memory(
        self,
        identity: IdentityContext,
        query: str,
        filters: dict[str, Any] | None = None,
        debug: bool = False,
        limit: int = 10,
    ) -> RetrievalResult:
        filters = filters or {}
        query_vector = self._normalize_vector(self._embeddings.embed(query))
        words = {w for w in query.lower().split() if w}
        now = datetime.now(tz=timezone.utc)

        scored: list[tuple[MemoryEntry, float, dict[str, float]]] = []
        for entry in self._memory.list_by_tenant(identity.tenant_id or ""):
            if not self._passes_filters(entry, filters, now):
                continue
            decision = self._policy.can_read_memory(identity, entry)
            if not decision.allowed:
                continue
            semantic = self._cosine_similarity(entry.embedding or [], query_vector)
            keyword = self._keyword_overlap(words, entry.content.lower().split())
            exact = 1.0 if query.lower() in entry.content.lower() else 0.0
            recency = self._recency_score(entry.created_at, now)
            importance = entry.importance / 100.0
            confidence = entry.confidence
            scope_priority = {"isolated": 1.0, "scoped": 0.85, "shared": 0.7}.get(entry.scope, 0.5)

            score = (
                semantic * 0.42
                + keyword * 0.18
                + recency * 0.12
                + importance * 0.14
                + confidence * 0.1
                + scope_priority * 0.04
                + exact * 0.08
            )
            scored.append(
                (
                    entry,
                    score,
                    {
                        "semantic": round(semantic, 4),
                        "keyword": round(keyword, 4),
                        "recency": round(recency, 4),
                        "importance": round(importance, 4),
                        "confidence": round(confidence, 4),
                        "scope_priority": round(scope_priority, 4),
                        "exact_match": round(exact, 4),
                        "hybrid_score": round(score, 4),
                    },
                )
            )

        scored.sort(key=lambda x: x[1], reverse=True)
        deduped: list[tuple[MemoryEntry, float, dict[str, float]]] = []
        seen_hash: set[str] = set()
        for row in scored:
            entry = row[0]
            if entry.content_hash and entry.content_hash in seen_hash:
                continue
            if entry.content_hash:
                seen_hash.add(entry.content_hash)
            deduped.append(row)
            if len(deduped) >= limit:
                break

        items: list[dict[str, Any]] = []
        for entry, score, components in deduped:
            payload = {
                "memory_id": entry.id,
                "content": entry.content,
                "scope": entry.scope,
                "entry_type": entry.entry_type,
                "tags": entry.tags,
                "source_ref": entry.source_ref,
                "content_hash": entry.content_hash,
                "confidence": entry.confidence,
                "importance": entry.importance,
                "source_label": entry.source_ref or f"memory:{entry.id}",
                "score": round(score, 4),
                "created_at": entry.created_at.isoformat(),
                "valid_from": entry.valid_from.isoformat() if entry.valid_from else None,
            }
            if debug:
                payload["debug"] = components
            items.append(payload)
        return RetrievalResult(
            items=items,
            debug={"query": query, "count": len(items), "filters": filters, "debug_mode": debug},
        )

    def _passes_filters(self, entry: MemoryEntry, filters: dict[str, Any], now: datetime) -> bool:
        if entry.metadata.get("soft_deleted") or entry.metadata.get("hard_deleted"):
            return False
        if filters.get("entry_type") and entry.entry_type != filters["entry_type"]:
            return False
        if filters.get("tag") and filters["tag"] not in entry.tags:
            return False
        if filters.get("domain") and f"domain:{filters['domain']}" not in entry.tags:
            return False
        if filters.get("source_ref") and entry.source_ref != filters["source_ref"]:
            return False
        if entry.valid_from and entry.valid_from > now:
            return False
        if entry.valid_until and entry.valid_until < now:
            return False
        return True

    def _keyword_overlap(self, query_words: set[str], content_words: list[str]) -> float:
        if not query_words:
            return 0.0
        matches = sum(1 for w in query_words if w in content_words)
        return matches / len(query_words)

    def _recency_score(self, created_at: datetime, now: datetime) -> float:
        age_days = max(0.0, (now - created_at).total_seconds() / 86400.0)
        return math.exp(-age_days / 30.0)

    def _normalize_vector(self, vector: list[float]) -> list[float]:
        norm = math.sqrt(sum(v * v for v in vector))
        if norm == 0:
            return vector
        return [v / norm for v in vector]

    def _cosine_similarity(self, a: list[float], b: list[float]) -> float:
        if not a or len(a) != len(b):
            return 0.0
        dot = sum(x * y for x, y in zip(a, b))
        norm_a = math.sqrt(sum(x * x for x in a))
        norm_b = math.sqrt(sum(y * y for y in b))
        if norm_a == 0 or norm_b == 0:
            return 0.0
        return dot / (norm_a * norm_b)

from __future__ import annotations

import hashlib
import math
import re
from dataclasses import dataclass
from datetime import datetime, timedelta, timezone
from typing import Any

from app.embeddings.service import EmbeddingService
from app.memory.models import MemoryEntry
from app.memory.service import MemoryService


@dataclass(frozen=True)
class IngestionResult:
    inserted: bool
    reason: str
    memory: MemoryEntry | None
    debug: dict[str, Any]


class MemoryIngestionWorker:
    def __init__(self, memory_service: MemoryService, embeddings: EmbeddingService) -> None:
        self._memory = memory_service
        self._embeddings = embeddings

    def ingest(
        self,
        tenant_id: str,
        owner_agent_id: str,
        scope: str,
        raw_content: str,
        source_ref: str | None = None,
        group_id: str | None = None,
        metadata: dict[str, Any] | None = None,
    ) -> IngestionResult:
        cleaned = self._normalize_content(raw_content)
        if not cleaned:
            return IngestionResult(False, "empty_after_normalization", None, {"raw_length": len(raw_content)})

        content_hash = hashlib.sha256(cleaned.encode("utf-8")).hexdigest()
        existing = self._memory.list_by_tenant(tenant_id)
        if any(m.content_hash == content_hash for m in existing):
            return IngestionResult(False, "duplicate_content_hash", None, {"content_hash": content_hash})
        if source_ref and any(m.source_ref == source_ref for m in existing):
            return IngestionResult(False, "duplicate_source_ref", None, {"source_ref": source_ref})

        embedding = self._embeddings.embed(cleaned)
        embedding = self._normalize_vector(embedding)
        if not self._embeddings.validate(embedding):
            return IngestionResult(False, "embedding_dimension_mismatch", None, {"dim": len(embedding)})
        near_dup = self._near_duplicate(existing, embedding, threshold=0.985)
        if near_dup:
            return IngestionResult(False, "near_duplicate", near_dup, {"duplicate_id": near_dup.id})

        entry_type = self._classify(cleaned)
        extracted = self._extract(cleaned)
        importance, confidence = self._score(cleaned, entry_type, extracted)
        valid_from, valid_until = self._validity_window(entry_type, confidence)
        tags = self._tag(cleaned, metadata or {}, extracted)

        memory = self._memory.create(
            tenant_id=tenant_id,
            owner_agent_id=owner_agent_id,
            scope=scope,
            content=cleaned,
            group_id=group_id,
            entry_type=entry_type,
            tags=tags,
            source_ref=source_ref,
            embedding=embedding,
            content_hash=content_hash,
            importance=importance,
            confidence=confidence,
            valid_from=valid_from,
            valid_until=valid_until,
            metadata={
                "raw_type": (metadata or {}).get("type"),
                "facts": extracted["facts"],
                "outcomes": extracted["outcomes"],
                "preferences": extracted["preferences"],
                "constraints": extracted["constraints"],
            },
        )
        return IngestionResult(
            True,
            "inserted",
            memory,
            {
                "entry_type": entry_type,
                "importance": importance,
                "confidence": confidence,
                "tags": tags,
                "content_hash": content_hash,
            },
        )

    def _normalize_content(self, raw: str) -> str:
        cleaned = re.sub(r"\s+", " ", raw).strip()
        boilerplate = [
            "Sent from my iPhone",
            "This message may contain confidential information.",
            "Generated by automated system.",
        ]
        for phrase in boilerplate:
            cleaned = cleaned.replace(phrase, "").strip()
        return re.sub(r"\s+", " ", cleaned).strip()

    def _classify(self, content: str) -> str:
        lowered = content.lower()
        if any(word in lowered for word in ("always", "never", "must", "prefer", "policy")):
            return "fact"
        if any(word in lowered for word in ("completed", "done", "resolved", "failed", "outcome")):
            return "episode"
        return "message"

    def _extract(self, content: str) -> dict[str, list[str]]:
        lowered = content.lower()
        facts = [content] if any(k in lowered for k in ("is ", "are ", "must", "never")) else []
        outcomes = [content] if any(k in lowered for k in ("completed", "resolved", "failed", "shipped")) else []
        preferences = [content] if any(k in lowered for k in ("prefer", "like", "avoid")) else []
        constraints = [content] if any(k in lowered for k in ("must", "cannot", "never", "required")) else []
        return {
            "facts": facts,
            "outcomes": outcomes,
            "preferences": preferences,
            "constraints": constraints,
        }

    def _score(self, content: str, entry_type: str, extracted: dict[str, list[str]]) -> tuple[int, float]:
        importance = 30 + min(40, len(content) // 8)
        if entry_type == "fact":
            importance += 20
        elif entry_type == "episode":
            importance += 10
        if extracted["constraints"]:
            importance += 10
        importance = max(0, min(100, importance))

        confidence = 0.4 + (0.2 if entry_type == "fact" else 0.1 if entry_type == "episode" else 0.0)
        if extracted["facts"]:
            confidence += 0.1
        confidence = max(0.0, min(1.0, confidence))
        return importance, confidence

    def _validity_window(self, entry_type: str, confidence: float) -> tuple[datetime, datetime | None]:
        now = datetime.now(tz=timezone.utc)
        if entry_type == "message":
            return now, now + timedelta(days=30)
        if confidence < 0.6:
            return now, now + timedelta(days=90)
        return now, None

    def _tag(self, content: str, metadata: dict[str, Any], extracted: dict[str, list[str]]) -> list[str]:
        tags: set[str] = set()
        for key in ("project", "user", "domain", "task_type"):
            value = metadata.get(key)
            if isinstance(value, str) and value:
                tags.add(f"{key}:{value}")
        if extracted["preferences"]:
            tags.add("category:preference")
        if extracted["constraints"]:
            tags.add("category:constraint")
        if "bug" in content.lower():
            tags.add("domain:engineering")
        return sorted(tags)

    def _near_duplicate(self, existing: list[MemoryEntry], candidate: list[float], threshold: float) -> MemoryEntry | None:
        for entry in existing:
            if not entry.embedding:
                continue
            sim = self._cosine_similarity(entry.embedding, candidate)
            if sim >= threshold:
                return entry
        return None

    def _normalize_vector(self, vector: list[float]) -> list[float]:
        norm = math.sqrt(sum(v * v for v in vector))
        if norm == 0:
            return vector
        return [v / norm for v in vector]

    def _cosine_similarity(self, a: list[float], b: list[float]) -> float:
        if len(a) != len(b):
            return -1.0
        dot = sum(x * y for x, y in zip(a, b))
        norm_a = math.sqrt(sum(x * x for x in a))
        norm_b = math.sqrt(sum(y * y for y in b))
        if norm_a == 0 or norm_b == 0:
            return -1.0
        return dot / (norm_a * norm_b)

